import{_ as i,o as a,c as e,a2 as t}from"./chunks/framework.CE5oItKu.js";const _=JSON.parse('{"title":"表单页 UI 规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/frontend/10-form-page.md","filePath":"mango-pmo/rules/frontend/10-form-page.md"}'),o={name:"mango-pmo/rules/frontend/10-form-page.md"};function r(n,l,s,d,h,c){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="表单页-ui-规范" tabindex="-1">表单页 UI 规范 <a class="header-anchor" href="#表单页-ui-规范" aria-label="Permalink to &quot;表单页 UI 规范&quot;">​</a></h1><h2 id="_1-页面结构" tabindex="-1">1. 页面结构 <a class="header-anchor" href="#_1-页面结构" aria-label="Permalink to &quot;1. 页面结构&quot;">​</a></h2><ol><li>表单页是下级页面，必须有返回栏。</li><li>返回栏只放返回图标和当前标题。</li><li>返回栏不放面包屑、状态、页面操作按钮。</li><li>页面级操作放到底部悬浮操作栏。</li><li>底部操作栏与内容区同宽。</li></ol><h2 id="_2-分组原则" tabindex="-1">2. 分组原则 <a class="header-anchor" href="#_2-分组原则" aria-label="Permalink to &quot;2. 分组原则&quot;">​</a></h2><p>表单不是接口字段容器，表单布局必须服务业务判断路径。</p><p>必须先分组，再排字段。每个分组都要回答一个明确业务问题，例如：</p><ul><li>业务识别：当前处理对象是谁。</li><li>核心判断：本次操作是否合理。</li><li>金额信息：原始金额、操作金额、剩余金额如何对比。</li><li>账户信息：收款、付款、退款、结算账户是否正确。</li><li>凭证与说明：上传依据、填写原因、补充备注。</li><li>状态与结果：状态、结果、失败原因。</li><li>时间与审计：谁在什么时候做了什么。</li></ul><h2 id="_3-字段顺序" tabindex="-1">3. 字段顺序 <a class="header-anchor" href="#_3-字段顺序" aria-label="Permalink to &quot;3. 字段顺序&quot;">​</a></h2><ol><li>表单不能按接口字段、数据库字段、返回字段顺序机械排列。</li><li>组内字段必须有业务顺序。</li><li>后面的字段要能参考前面的字段。</li><li>典型顺序为：基础值 -&gt; 操作值 -&gt; 计算结果 -&gt; 状态/结论。</li><li>有对比、级联、依赖、计算关系的字段必须放在同一组、相邻行。</li></ol><p>示例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>可退金额 -&gt; 退款金额 -&gt; 剩余金额 -&gt; 退款类型</span></span></code></pre></div><h2 id="_4-label-与布局" tabindex="-1">4. Label 与布局 <a class="header-anchor" href="#_4-label-与布局" aria-label="Permalink to &quot;4. Label 与布局&quot;">​</a></h2><ol><li>后台表单默认使用左 label、右内容。</li><li>宽度足够时，不默认使用上下结构。</li><li>长文本、上传、JSON、富文本、复杂控件、移动端窄屏可以使用上下结构。</li><li>多列布局不追求填满，要看字段长度和阅读重量。</li><li>短字段可以并排，例如状态、类型、金额、日期、开关、短编码。</li><li>长字段独占整行，例如名称、地址、开户行、URL、备注、原因、说明、上传、JSON。</li><li>禁止两个长字段强行左右并排。</li><li>禁止为了凑列拆散强关联字段。</li></ol><h2 id="_5-技术字段" tabindex="-1">5. 技术字段 <a class="header-anchor" href="#_5-技术字段" aria-label="Permalink to &quot;5. 技术字段&quot;">​</a></h2><p>内部 ID、规则 ID、JSON、扩展参数、报文、低频审计信息必须后置、折叠或放入独立技术信息分组。</p><h2 id="_6-操作区" tabindex="-1">6. 操作区 <a class="header-anchor" href="#_6-操作区" aria-label="Permalink to &quot;6. 操作区&quot;">​</a></h2><ol><li>表单主操作固定在底部操作栏。</li><li>按钮顺序为：取消 -&gt; 保存/确认。</li><li>一个操作区只能有一个 <code>primary</code>。</li><li>危险操作使用 <code>danger</code>，并带二次确认。</li><li>提交中必须 loading，禁止重复提交。</li><li>未保存离开或关闭时必须提醒确认。</li></ol><h2 id="_7-检查清单" tabindex="-1">7. 检查清单 <a class="header-anchor" href="#_7-检查清单" aria-label="Permalink to &quot;7. 检查清单&quot;">​</a></h2><ol><li>是否按业务判断分组。</li><li>每组是否有明确业务依据。</li><li>字段顺序是否符合业务先后。</li><li>对比、级联、计算字段是否相邻。</li><li>长字段是否独占整行。</li><li>label 是否默认左右结构。</li><li>技术字段是否后置。</li><li>操作区是否稳定、提交态是否完整。</li></ol>',19)])])}const u=i(o,[["render",r]]);export{_ as __pageData,u as default};
